const SEC_NEXTJS = {
  id: "nextjs",
  title: "Next.js",
  icon: "▲",
  ib: "rgba(0, 0, 0, 0.2)",
  ic: "#FFFFFF",
  grp: "frontend",
  bar: "#000000",
  tglow: "rgba(0, 0, 0, 0.3)",
  desc: "Master Next.js fundamentals, routing, data fetching, optimization, API routes, deployment, and production best practices.",
  tags: ["nextjs", "react", "ssr", "ssg", "routing", "api-routes", "deployment", "typescript"],
  qs: [
    // ==================== FUNDAMENTALS (15 questions) ====================
    {q: "What is Next.js and what are its main benefits?", d: "easy", a: "<p><strong>Next.js:</strong> A React framework for production-grade applications built on top of React.</p><p><strong>Key Benefits:</strong></p><ul><li><strong>Server-Side Rendering (SSR):</strong> Render pages on server for better SEO and performance</li><li><strong>Static Site Generation (SSG):</strong> Pre-render pages at build time for fast delivery</li><li><strong>Hybrid Rendering:</strong> Mix SSR, SSG, and client-side rendering in same app</li><li><strong>API Routes:</strong> Built-in backend with serverless functions</li><li><strong>Automatic Code Splitting:</strong> Only load JavaScript needed for each page</li><li><strong>Image Optimization:</strong> Automatic modern format delivery and responsive sizing</li><li><strong>Built-in CSS Support:</strong> CSS modules, Tailwind CSS, PostCSS out of the box</li><li><strong>TypeScript Support:</strong> First-class TypeScript support with zero configuration</li><li><strong>Fast Refresh:</strong> Reliable live editing experience</li><li><strong>Deployment:</strong> Optimized for Vercel, but deployable anywhere</li></ul>"},

    {q: "What's the difference between Next.js Pages Router and App Router?", d: "medium", a: "<p><strong>Pages Router (Legacy):</strong> File-based routing in /pages directory. Introduced in Next.js 9.</p><pre><code>// pages/about.js\nexport default function About() {\n  return &lt;h1&gt;About Page&lt;/h1&gt;;\n}\n\n// pages/posts/[id].js (dynamic route)</code></pre><p><strong>App Router (New):</strong> File-based routing in /app directory with better patterns. Introduced in Next.js 13.</p><pre><code>// app/about/page.js\nexport default function About() {\n  return &lt;h1&gt;About Page&lt;/h1&gt;;\n}\n\n// app/posts/[id]/page.js (dynamic route)</code></pre><p><strong>Key Differences:</strong></p><table><tr><th>Feature</th><th>Pages Router</th><th>App Router</th></tr><tr><td>Server/Client Components</td><td>Client by default</td><td>Server by default</td></tr><tr><td>Data Fetching</td><td>getServerSideProps, getStaticProps</td><td>Server Components, fetch()</td></tr><tr><td>Layouts</td><td>Per-page wrapper</td><td>Nested layouts</td></tr><tr><td>Error Handling</td><td>Custom _error.js</td><td>error.js boundary</td></tr><tr><td>Loading States</td><td>Manual or libraries</td><td>loading.js automatic</td></tr><tr><td>Performance</td><td>Good</td><td>Better (smaller JS)</td></tr></table><p><strong>Status:</strong> Pages Router still supported. App Router is recommended for new projects.</p>"},

    {q: "What is Server-Side Rendering (SSR) and when should you use it?", d: "easy", a: "<p><strong>SSR:</strong> Generate HTML on the server for each request and send to client.</p><pre><code>// pages/posts.js (Pages Router)\nexport async function getServerSideProps() {\n  const res = await fetch('https://api.example.com/posts');\n  const posts = await res.json();\n  \n  return {\n    props: { posts },\n    revalidate: 10 // Revalidate every 10 seconds\n  };\n}\n\nexport default function Posts({ posts }) {\n  return &lt;div&gt;{/* render posts */}&lt;/div&gt;;\n}</code></pre><p><strong>When to Use SSR:</strong></p><ul><li>Content changes frequently (personalized content, real-time data)</li><li>User authentication required</li><li>Dynamic content based on request parameters</li><li>Cannot pre-render at build time</li></ul><p><strong>Benefits:</strong></p><ul><li>Fresh data on every request</li><li>Good for SEO (content in initial HTML)</li><li>Secure (sensitive logic on server)</li></ul><p><strong>Drawbacks:</strong></p><ul><li>Slower than static pages (server-side latency)</li><li>Increases server load</li><li>Cannot use CDN effectively</li></ul>"},

    {q: "What is Static Site Generation (SSG) and when should you use it?", d: "easy", a: "<p><strong>SSG:</strong> Generate HTML at build time and reuse for all requests.</p><pre><code>// pages/posts.js\nexport async function getStaticProps() {\n  const res = await fetch('https://api.example.com/posts');\n  const posts = await res.json();\n  \n  return {\n    props: { posts },\n    revalidate: 3600 // Revalidate every hour (ISR)\n  };\n}\n\nexport default function Posts({ posts }) {\n  return &lt;div&gt;{/* render posts */}&lt;/div&gt;;\n}</code></pre><p><strong>When to Use SSG:</strong></p><ul><li>Content doesn't change often</li><li>Same content for all users (blog posts, docs)</li><li>Can be pre-rendered</li><li>Performance-critical pages</li></ul><p><strong>Benefits:</strong></p><ul><li>Extremely fast (serves static HTML)</li><li>CDN-friendly</li><li>Scales globally without server cost</li><li>Best SEO</li><li>No server required</li></ul><p><strong>Drawbacks:</strong></p><ul><li>Content stale until rebuild</li><li>Build time increases with more pages</li><li>Cannot show user-specific data</li></ul><p><strong>Solution:</strong> Use Incremental Static Regeneration (ISR) with revalidate to update without full rebuild.</p>"},

    {q: "What is Incremental Static Regeneration (ISR)?", d: "medium", a: "<p><strong>ISR:</strong> Update static pages after deployment without rebuilding entire site.</p><pre><code>export async function getStaticProps() {\n  const data = await fetchData();\n  \n  return {\n    props: { data },\n    revalidate: 60 // Revalidate every 60 seconds\n  };\n}\n\n// App Router equivalent:\nexport const revalidate = 60;</code></pre><p><strong>How ISR Works:</strong></p><ol><li>Page generated and cached at build time</li><li>User requests page - receives cached version</li><li>After revalidate interval, next request triggers background regeneration</li><li>User gets updated page on subsequent request</li></ol><p><strong>Stale-While-Revalidate Pattern:</strong></p><pre><code>// User gets stale data while page regenerates in background\n// Next request gets fresh data\nreturn {\n  props: { data },\n  revalidate: 3600 // Regenerate every hour\n};</code></pre><p><strong>Use Cases:</strong></p><ul><li>Blog posts with occasional edits</li><li>Product catalogs</li><li>Marketing pages</li><li>Documentation sites</li></ul><p><strong>Benefits:</strong></p><ul><li>Combines speed of SSG with freshness of SSR</li><li>No full rebuild needed</li><li>Scales to millions of pages</li><li>Cost-efficient</li></ul>"},

    {q: "What is Client-Side Rendering (CSR) in Next.js?", d: "easy", a: "<p><strong>CSR:</strong> Fetch data and render content in the browser using JavaScript.</p><pre><code>import { useState, useEffect } from 'react';\n\nexport default function Posts() {\n  const [posts, setPosts] = useState([]);\n  const [loading, setLoading] = useState(true);\n  \n  useEffect(() => {\n    fetch('/api/posts')\n      .then(res =&gt; res.json())\n      .then(data =&gt; {\n        setPosts(data);\n        setLoading(false);\n      });\n  }, []);\n  \n  if (loading) return &lt;div&gt;Loading...&lt;/div&gt;;\n  return &lt;div&gt;{/* render posts */}&lt;/div&gt;;\n}</code></pre><p><strong>When to Use CSR:</strong></p><ul><li>Content requires user authentication</li><li>Highly dynamic, frequently changing data</li><li>Page doesn't need SEO (dashboards, internal tools)</li><li>Initial load isn't performance-critical</li></ul><p><strong>Benefits:</strong></p><ul><li>Less server load</li><li>Interactive experience</li><li>Works offline with service workers</li></ul><p><strong>Drawbacks:</strong></p><ul><li>Slower initial page load</li><li>No content in initial HTML (SEO issues)</li><li>Larger JavaScript bundle</li><li>Flash of unstyled content (FOUC)</li></ul><p><strong>Best Practice:</strong> Use hybrid rendering - SSG/SSR for public content, CSR for user-specific data.</p>"},

    {q: "What are Server Components and Client Components in App Router?", d: "hard", a: "<p><strong>Server Components (Default):</strong> React components that run only on the server. Never sent to browser.</p><pre><code>// app/posts/page.js (Server Component by default)\nimport { sql } from '@vercel/postgres';\n\nexport default async function Posts() {\n  const { rows } = await sql`SELECT * FROM posts`;\n  \n  return (\n    &lt;div&gt;\n      {rows.map(post =&gt; (\n        &lt;article key={post.id}&gt;{post.title}&lt;/article&gt;\n      ))}\n    &lt;/div&gt;\n  );\n}</code></pre><p><strong>Client Components:</strong> React components that run in the browser. Can use hooks, state, effects.</p><pre><code>'use client';\n\nimport { useState } from 'react';\n\nexport default function Counter() {\n  const [count, setCount] = useState(0);\n  \n  return (\n    &lt;button onClick={() =&gt; setCount(count + 1)}&gt;\n      Count: {count}\n    &lt;/button&gt;\n  );\n}</code></pre><p><strong>Key Differences:</strong></p><table><tr><th>Aspect</th><th>Server Components</th><th>Client Components</th></tr><tr><td>Execution</td><td>Server only</td><td>Browser</td></tr><tr><td>Bundle Size</td><td>No impact</td><td>Increases bundle</td></tr><tr><td>Access Secrets</td><td>✓ Yes</td><td>✗ No</td></tr><tr><td>Direct DB Access</td><td>✓ Yes</td><td>✗ No (use API)</td></tr><tr><td>Use Hooks</td><td>✗ No</td><td>✓ Yes</td></tr><tr><td>Event Listeners</td><td>✗ No</td><td>✓ Yes</td></tr><tr><td>State Management</td><td>✗ No</td><td>✓ Yes</td></tr></table><p><strong>Best Practice:</strong> Use Server Components by default, use Client Components only when needed for interactivity.</p>"},

    {q: "How does Next.js handle environment variables?", d: "medium", a: "<p><strong>Environment Variables in Next.js:</strong> Securely manage secrets and configuration.</p><p><strong>File Naming:</strong></p><pre><code>.env.local          // Local overrides (not committed)\n.env.development    // Development environment\n.env.production     // Production environment\n.env               // Shared defaults</code></pre><p><strong>Exposing to Browser (PUBLIC):</strong></p><pre><code>// .env.local\nNEXT_PUBLIC_API_URL=https://api.example.com  // Exposed to browser\nDATABASE_URL=postgresql://...                 // Secret, server-only</code></pre><p><strong>Usage:</strong></p><pre><code>// Server-side (pages, API routes)\nconst dbUrl = process.env.DATABASE_URL;\n\n// Client-side (components)\nconst apiUrl = process.env.NEXT_PUBLIC_API_URL;\n\n// Browser console\nconsole.log(process.env.NEXT_PUBLIC_API_URL); // Works\nconsole.log(process.env.DATABASE_URL);        // undefined</code></pre><p><strong>Important Rules:</strong></p><ul><li>Only variables prefixed with NEXT_PUBLIC_ are exposed to browser</li><li>All vars available in Node.js/server context</li><li>Changes to .env require server restart</li><li>Never commit .env.local to git</li><li>Use .env.example for documentation</li></ul>"},

    {q: "What is the project structure of a Next.js application?", d: "easy", a: "<p><strong>Typical Next.js Project Structure (App Router):</strong></p><pre><code>my-app/\n├── app/                          # Main app directory\n│   ├── layout.js                 # Root layout\n│   ├── page.js                   # Home page (/)\n│   ├── posts/\n│   │   ├── page.js              # /posts\n│   │   ├── layout.js            # /posts layout\n│   │   └── [id]/\n│   │       ├── page.js          # /posts/[id] (dynamic)\n│   │       └── loading.js       # Loading UI\n│   ├── api/\n│   │   ├── posts/\n│   │   │   └── route.js         # GET /api/posts\n│   │   └── posts/[id]/\n│   │       └── route.js         # GET /api/posts/[id]\n│   ├── error.js                 # Error boundary\n│   └── not-found.js             # 404 page\n├── public/                       # Static assets\n│   ├── images/\n│   └── favicon.ico\n├── styles/                       # Global styles\n│   └── globals.css\n├── lib/                          # Utility functions\n│   └── db.js\n├── .env.local                    # Environment variables\n├── .env.example                  # Environment template\n├── next.config.js                # Next.js configuration\n├── tsconfig.json                 # TypeScript config\n├── package.json\n└── README.md</code></pre><p><strong>Key Directories:</strong></p><ul><li><strong>app/:</strong> Main application code (App Router)</li><li><strong>public/:</strong> Static files (images, fonts, etc.)</li><li><strong>styles/:</strong> CSS files</li><li><strong>lib/:</strong> Shared utilities and helpers</li></ul>"},

    {q: "How do you configure Next.js with next.config.js?", d: "medium", a: "<p><strong>next.config.js:</strong> Configuration file for Next.js build and runtime behavior.</p><pre><code>/** @type {import('next').NextConfig} */\nconst nextConfig = {\n  // Enable React strict mode\n  reactStrictMode: true,\n  \n  // Image optimization\n  images: {\n    remotePatterns: [\n      {\n        protocol: 'https',\n        hostname: 'example.com',\n      },\n    ],\n  },\n  \n  // Environment variables\n  env: {\n    CUSTOM_VAR: 'value',\n  },\n  \n  // Headers\n  async headers() {\n    return [\n      {\n        source: '/api/:path*',\n        headers: [\n          { key: 'Cache-Control', value: 'public, max-age=3600' },\n        ],\n      },\n    ];\n  },\n  \n  // Redirects\n  async redirects() {\n    return [\n      {\n        source: '/old-path',\n        destination: '/new-path',\n        permanent: true, // 308 redirect\n      },\n    ];\n  },\n  \n  // Rewrites\n  async rewrites() {\n    return {\n      beforeFiles: [\n        {\n          source: '/api/:path*',\n          destination: 'https://external-api.com/:path*',\n        },\n      ],\n    };\n  },\n  \n  // Webpack custom config\n  webpack: (config, { isServer }) => {\n    return config;\n  },\n};\n\nmodule.exports = nextConfig;</code></pre><p><strong>Common Configurations:</strong></p><ul><li><strong>reactStrictMode:</strong> Enable React strict mode (development warnings)</li><li><strong>swcMinify:</strong> Use SWC for minification (faster)</li><li><strong>pageExtensions:</strong> Specify page file extensions</li><li><strong>basePath:</strong> Prefix all routes with base path</li><li><strong>i18n:</strong> Internationalization configuration</li></ul>"},

    {q: "What is Fast Refresh and how does it work?", d: "medium", a: "<p><strong>Fast Refresh:</strong> Reliable live editing experience during development. Preserves component state while updating code.</p><pre><code>// Before Fast Refresh: Full page reload, state lost\n// After Fast Refresh: Only component updates, state preserved\n\nexport default function Counter() {\n  const [count, setCount] = useState(0);\n  \n  // Edit this text while dev server running\n  // State preserved!\n  return &lt;button&gt;Count: {count}&lt;/button&gt;;\n}</code></pre><p><strong>How It Works:</strong></p><ol><li>You save a file</li><li>Dev server detects change</li><li>Fast Refresh re-executes module</li><li>Component state preserved (if possible)</li><li>UI updates without full reload</li></ol><p><strong>Limitations (Full reload triggered):</strong></p><ul><li>Export default is class component</li><li>Export is named export (not default)</li><li>File has no React exports</li><li>Using higher-order components</li></ul><p><strong>Best Practice:</strong> Use functional components with hooks for best Fast Refresh experience.</p>"},

    {q: "How does Next.js optimize images?", d: "medium", a: "<p><strong>Next/Image Component:</strong> Automatic image optimization and responsive loading.</p><pre><code>import Image from 'next/image';\n\nexport default function Profile() {\n  return (\n    &lt;Image\n      src=\"/profile.jpg\"\n      alt=\"Profile\"\n      width={200}\n      height={200}\n      priority={true}  // Load immediately (LCP)\n      sizes=\"(max-width: 768px) 100vw, 50vw\"\n    /&gt;\n  );\n}</code></pre><p><strong>Optimizations:</strong></p><ul><li><strong>Automatic Format:</strong> Serve WebP/AVIF to modern browsers</li><li><strong>Responsive Images:</strong> Generate multiple sizes, serve appropriate one</li><li><strong>Lazy Loading:</strong> Load below-fold images on demand</li><li><strong>Placeholder:</strong> Show blur placeholder while loading</li><li><strong>Size Optimization:</strong> Prevent layout shift</li></ul><p><strong>Configuration:</strong></p><pre><code>// next.config.js\nconst nextConfig = {\n  images: {\n    remotePatterns: [\n      { protocol: 'https', hostname: 'example.com' },\n    ],\n    deviceSizes: [640, 750, 828, 1080, 1200, 1920],\n    imageSizes: [16, 32, 48, 64, 96, 128, 256, 384],\n    minimumCacheTTL: 60,\n  },\n};\n</code></pre><p><strong>Benefits:</strong></p><ul><li>Faster page load</li><li>Better Core Web Vitals</li><li>Reduced bandwidth</li><li>Modern format delivery</li></ul>"},

    {q: "What are Middleware in Next.js and how do you use them?", d: "hard", a: "<p><strong>Middleware:</strong> Code that runs before request is processed. Useful for authentication, logging, redirects.</p><pre><code>// middleware.js (App Router)\nimport { NextResponse } from 'next/server';\nimport type { NextRequest } from 'next/server';\n\nexport function middleware(request: NextRequest) {\n  // Get token from cookies\n  const token = request.cookies.get('auth')?.value;\n  \n  // Redirect unauthenticated users\n  if (!token &amp;&amp; request.nextUrl.pathname.startsWith('/dashboard')) {\n    return NextResponse.redirect(new URL('/login', request.url));\n  }\n  \n  // Continue to next middleware or route\n  return NextResponse.next();\n}\n\n// Configure which routes middleware runs on\nexport const config = {\n  matcher: [\n    '/dashboard/:path*',\n    '/api/:path*',\n  ],\n};</code></pre><p><strong>Use Cases:</strong></p><ul><li>Authentication/authorization</li><li>Request logging and monitoring</li><li>Redirects and URL rewrites</li><li>Adding headers</li><li>Rate limiting</li><li>A/B testing</li><li>Locale detection</li></ul><p><strong>Middleware Rules:</strong></p><ul><li>Must be in root directory as middleware.js or middleware.ts</li><li>Runs before pages are served</li><li>No access to response body</li><li>Can modify headers and redirect</li><li>Cannot write files</li></ul>"},

    {q: "What is Partial Pre-rendering (PPR) in Next.js?", d: "hard", a: "<p><strong>PPR:</strong> New rendering strategy combining static and dynamic content. Available in Next.js 15+.</p><pre><code>// app/dashboard/page.js\nimport { Suspense } from 'react';\n\n// Static content\nfunction Header() {\n  return &lt;h1&gt;Dashboard&lt;/h1&gt;;\n}\n\n// Dynamic content\nasync function DynamicStats() {\n  const stats = await fetchStats();\n  return &lt;div&gt;{/* render stats */}&lt;/div&gt;\n}\n\nexport default function Dashboard() {\n  return (\n    &lt;&gt;\n      &lt;Header /&gt;  {/* Static */}\n      &lt;Suspense fallback={&lt;div&gt;Loading stats...&lt;/div&gt;}&gt;\n        &lt;DynamicStats /&gt;  {/* Dynamic */}\n      &lt;/Suspense&gt;\n    &lt;/&gt;\n  );\n}</code></pre><p><strong>How PPR Works:</strong></p><ol><li>Static shell renders and caches at build time</li><li>Dynamic content fetches at request time</li><li>Static HTML sent immediately to user</li><li>Dynamic content streams in when ready</li></ol><p><strong>Benefits:</strong></p><ul><li>Faster initial page load (static parts cached)</li><li>Fresh dynamic data (fetched per request)</li><li>Best of both SSG and SSR</li><li>Better performance than full SSR</li></ul><p><strong>When to Use:</strong></p><ul><li>Mostly static pages with some dynamic sections</li><li>Dashboards and admin panels</li><li>E-commerce product pages with reviews</li></ul>"},

    {q: "How do you implement authentication in Next.js?", d: "hard", a: "<p><strong>Authentication Approaches:</strong></p><p><strong>1. JWT with Cookies:</strong></p><pre><code>// app/api/login/route.js\nexport async function POST(request) {\n  const { email, password } = await request.json();\n  \n  // Validate credentials\n  const user = await db.user.findUnique({ where: { email } });\n  if (!user || !(await bcrypt.compare(password, user.password))) {\n    return Response.json({ error: 'Invalid credentials' }, { status: 401 });\n  }\n  \n  // Create JWT\n  const token = jwt.sign({ userId: user.id }, process.env.JWT_SECRET);\n  \n  // Set secure httpOnly cookie\n  const response = Response.json({ success: true });\n  response.cookies.set('auth', token, {\n    httpOnly: true,\n    secure: process.env.NODE_ENV === 'production',\n    sameSite: 'strict',\n  });\n  \n  return response;\n}</code></pre><p><strong>2. NextAuth.js (Recommended):</strong></p><pre><code>// app/api/auth/[...nextauth]/route.js\nimport NextAuth from 'next-auth';\nimport CredentialsProvider from 'next-auth/providers/credentials';\n\nconst handler = NextAuth({\n  providers: [\n    CredentialsProvider({\n      async authorize(credentials) {\n        const user = await db.user.findUnique({\n          where: { email: credentials.email }\n        });\n        \n        if (user &amp;&amp; await bcrypt.compare(credentials.password, user.password)) {\n          return user;\n        }\n        return null;\n      },\n    }),\n  ],\n});\n\nexport { handler as GET, handler as POST };</code></pre><p><strong>3. Middleware for Protected Routes:</strong></p><pre><code>// middleware.js\nimport { auth } from '@/auth';\n\nexport async function middleware(request) {\n  const session = await auth();\n  \n  if (!session &amp;&amp; request.nextUrl.pathname.startsWith('/dashboard')) {\n    return Response.redirect(new URL('/login', request.url));\n  }\n}\n\nexport const config = {\n  matcher: ['/dashboard/:path*', '/api/protected/:path*'],\n};</code></pre><p><strong>Best Practices:</strong></p><ul><li>Use httpOnly cookies for JWT (immune to XSS)</li><li>Set secure flag in production</li><li>Implement CSRF protection</li><li>Use NextAuth.js for production apps</li><li>Hash passwords with bcrypt</li><li>Validate tokens on every request</li></ul>"},

    // ==================== ROUTING (18 questions) ====================
    {q: "How does file-based routing work in Next.js?", d: "easy", a: "<p><strong>File-Based Routing:</strong> Routes automatically created based on file structure in /app or /pages directory.</p><pre><code>// App Router (Next.js 13+)\napp/\n├── page.js                  → /\n├── about/\n│   └── page.js             → /about\n├── posts/\n│   ├── page.js             → /posts\n│   └── [id]/\n│       └── page.js         → /posts/1, /posts/2, etc\n├── dashboard/\n│   └── (auth)/             // Route group - doesn't affect URL\n│       └── profile/\n│           └── page.js     → /dashboard/profile</code></pre><p><strong>File Conventions:</strong></p><ul><li><strong>page.js:</strong> Page component (UI rendered)</li><li><strong>layout.js:</strong> Shared layout for route segment</li><li><strong>loading.js:</strong> Loading UI while content loads</li><li><strong>error.js:</strong> Error boundary for segment</li><li><strong>not-found.js:</strong> Custom 404 page</li><li><strong>route.js:</strong> API endpoint</li></ul><p><strong>Dynamic Routes:</strong></p><ul><li><strong>[id]:</strong> Catch single segment (e.g., /posts/123)</li><li><strong>[...slug]:</strong> Catch all segments (e.g., /docs/a/b/c)</li><li><strong>[[...slug]]:</strong> Optional catch-all</li></ul>"},

    {q: "What is the difference between static and dynamic route segments?", d: "medium", a: "<p><strong>Static Segments:</strong> Fixed path parts that don't change.</p><pre><code>// app/posts/page.js → /posts (static)\n// app/about/page.js → /about (static)</code></pre><p><strong>Dynamic Segments:</strong> Variable path parts that change based on parameters.</p><pre><code>// app/posts/[id]/page.js\nexport default function Post({ params }) {\n  const { id } = params;\n  return &lt;h1&gt;Post {id}&lt;/h1&gt;;\n}\n\n// Matches: /posts/1, /posts/2, /posts/abc</code></pre><p><strong>Catch-All Routes:</strong></p><pre><code>// app/docs/[...slug]/page.js\nexport default function Doc({ params }) {\n  const { slug } = params; // Array: ['getting', 'started']\n  return &lt;h1&gt;{slug.join('/')}&lt;/h1&gt;;\n}\n\n// Matches: /docs/getting/started (slug=['getting','started'])</code></pre><p><strong>Optional Catch-All:</strong></p><pre><code>// app/docs/[[...slug]]/page.js\n// Matches /docs, /docs/getting, /docs/getting/started</code></pre>"},

    {q: "How do you access URL parameters in Next.js?", d: "easy", a: "<p><strong>In Page Component:</strong></p><pre><code>// app/posts/[id]/page.js\nexport default function Post({ params, searchParams }) {\n  const { id } = params;              // /posts/123 → id = '123'\n  const { sort } = searchParams;      // /posts/123?sort=date → sort = 'date'\n  \n  return (\n    &lt;div&gt;\n      &lt;h1&gt;Post {id}&lt;/h1&gt;\n      {sort &amp;&amp; &lt;p&gt;Sorted by: {sort}&lt;/p&gt;}\n    &lt;/div&gt;\n  );\n}</code></pre><p><strong>In API Route:</strong></p><pre><code>// app/api/posts/[id]/route.js\nexport async function GET(request, { params }) {\n  const { id } = params;\n  const { searchParams } = new URL(request.url);\n  const sort = searchParams.get('sort');\n  \n  return Response.json({ id, sort });\n}</code></pre><p><strong>Client-Side (Component):</strong></p><pre><code>'use client';\n\nimport { useSearchParams } from 'next/navigation';\n\nexport default function Component() {\n  const searchParams = useSearchParams();\n  const query = searchParams.get('q');\n  \n  return &lt;p&gt;Searching for: {query}&lt;/p&gt;;\n}</code></pre>"},

    {q: "What are Route Groups and why would you use them?", d: "medium", a: "<p><strong>Route Groups:</strong> Folders with parentheses that group routes without affecting URL.</p><pre><code>// (group-name) doesn't appear in URL\napp/\n├── (marketing)/\n│   ├── layout.js\n│   ├── page.js              → /\n│   ├── about/page.js        → /about\n│   └── contact/page.js      → /contact\n├── (admin)/\n│   ├── layout.js\n│   ├── dashboard/page.js    → /dashboard\n│   └── users/page.js        → /users\n└── api/\n    └── route.js             → /api</code></pre><p><strong>Use Cases:</strong></p><ul><li><strong>Organize Routes:</strong> Group related pages without URL changes</li><li><strong>Separate Layouts:</strong> Different layouts for different sections</li><li><strong>Create Isolated Segments:</strong> Each group has own layout hierarchy</li><li><strong>Authentication Middleware:</strong> Apply middleware to specific groups</li></ul><p><strong>Multiple Groups with Same Layout:</strong></p><pre><code>// (auth)/layout.js - layout for all auth routes\n// (auth)/login/page.js → /login\n// (auth)/signup/page.js → /signup\n// (auth)/forgot-password/page.js → /forgot-password</code></pre>"},

    {q: "How do you create parallel routes in Next.js?", d: "hard", a: "<p><strong>Parallel Routes:</strong> Render multiple segments in same route simultaneously.</p><pre><code>// Folder structure with @ prefix\napp/\n├── dashboard/\n│   ├── layout.js\n│   ├── page.js\n│   ├── @analytics/\n│   │   └── page.js\n│   ├── @team/\n│   │   └── page.js\n│   └── @settings/\n│       └── page.js</code></pre><p><strong>Usage in Layout:</strong></p><pre><code>// app/dashboard/layout.js\nexport default function Layout({\n  children,\n  analytics,\n  team,\n  settings,\n}) {\n  return (\n    &lt;&gt;\n      &lt;div className='content'&gt;{children}&lt;/div&gt;\n      &lt;div className='sidebar'&gt;\n        &lt;section&gt;{analytics}&lt;/section&gt;\n        &lt;section&gt;{team}&lt;/section&gt;\n        &lt;section&gt;{settings}&lt;/section&gt;\n      &lt;/div&gt;\n    &lt;/&gt;\n  );\n}</code></pre><p><strong>Use Cases:</strong></p><ul><li>Sidebars and main content</li><li>Independent sections that can render/update separately</li><li>Modals overlaid on top of content</li><li>Team feeds and activity feeds together</li></ul><p><strong>Conditional Rendering:</strong></p><pre><code>// Render nothing if not matching route\nif (!slug) return null;</code></pre>"},

    {q: "How do you implement SEO in Next.js?", d: "hard", a: "<p><strong>Metadata API:</strong> Define meta tags for each page.</p><pre><code>// app/posts/[id]/page.js\nexport async function generateMetadata({ params }) {\n  const post = await fetchPost(params.id);\n  \n  return {\n    title: post.title,\n    description: post.excerpt,\n    authors: [{ name: post.author }],\n    openGraph: {\n      type: 'article',\n      url: `https://example.com/posts/${params.id}`,\n      title: post.title,\n      description: post.excerpt,\n      images: [{ url: post.image }],\n    },\n    twitter: {\n      card: 'summary_large_image',\n      title: post.title,\n      description: post.excerpt,\n      images: [post.image],\n    },\n  };\n}\n\nexport default function Post({ params }) {\n  return &lt;article&gt;{/* content */}&lt;/article&gt;;\n}</code></pre><p><strong>Structured Data:</strong></p><pre><code>export default function Post({ params }) {\n  return (\n    &lt;&gt;\n      &lt;script\n        type='application/ld+json'\n        dangerouslySetInnerHTML={{\n          __html: JSON.stringify({\n            '@context': 'https://schema.org',\n            '@type': 'BlogPosting',\n            headline: post.title,\n            author: post.author,\n            datePublished: post.date,\n          }),\n        }}\n      /&gt;\n      &lt;article&gt;{/* content */}&lt;/article&gt;\n    &lt;/&gt;\n  );\n}</code></pre><p><strong>Sitemap and Robots:</strong></p><pre><code>// app/sitemap.ts\nexport default async function sitemap() {\n  const posts = await getPosts();\n  return posts.map(post =&gt; ({\n    url: `https://example.com/posts/${post.id}`,\n    lastModified: post.updated,\n    changeFrequency: 'weekly',\n    priority: 0.8,\n  }));\n}\n\n// app/robots.ts\nexport default {\n  rules: [\n    {\n      userAgent: '*',\n      allow: '/',\n      disallow: '/admin',\n    },\n  ],\n  sitemap: 'https://example.com/sitemap.xml',\n};</code></pre>"},

    {q: "How do you implement URL rewriting and redirects?", d: "medium", a: "<p><strong>Redirects (Next.js 13+):</strong></p><pre><code>// app/old-page/page.js\nimport { redirect } from 'next/navigation';\n\nexport default function OldPage() {\n  redirect('/new-page');\n}\n\n// In middleware\nimport { NextResponse } from 'next/server';\n\nexport function middleware(request) {\n  if (request.nextUrl.pathname === '/old') {\n    return NextResponse.redirect(new URL('/new', request.url));\n  }\n}</code></pre><p><strong>URL Rewriting:</strong> URL changes server-side, visible in browser as original.</p><pre><code>// next.config.js\nconst nextConfig = {\n  async rewrites() {\n    return {\n      beforeFiles: [\n        {\n          source: '/about',\n          destination: '/pages/about',\n        },\n      ],\n      afterFiles: [\n        {\n          source: '/docs/:path*',\n          destination: '/documentation/:path*',\n        },\n      ],\n      fallback: [\n        {\n          source: '/:path*',\n          destination: 'https://external-api.com/:path*',\n        },\n      ],\n    };\n  },\n};</code></pre><p><strong>Difference:</strong></p><ul><li><strong>Redirect:</strong> URL changes in browser (308 or 301)</li><li><strong>Rewrite:</strong> URL stays same, content from different destination</li></ul>"},

    {q: "What is an API Route and how do you create one?", d: "easy", a: "<p><strong>API Routes:</strong> Handle HTTP requests at specific endpoints.</p><pre><code>// app/api/posts/route.js\nexport async function GET(request) {\n  const posts = await db.post.findMany();\n  return Response.json(posts);\n}\n\nexport async function POST(request) {\n  const data = await request.json();\n  const post = await db.post.create({ data });\n  return Response.json(post, { status: 201 });\n}\n\n// Handles: GET /api/posts, POST /api/posts</code></pre><p><strong>Dynamic API Routes:</strong></p><pre><code>// app/api/posts/[id]/route.js\nexport async function GET(request, { params }) {\n  const post = await db.post.findUnique({\n    where: { id: params.id }\n  });\n  \n  if (!post) {\n    return Response.json(\n      { error: 'Not found' },\n      { status: 404 }\n    );\n  }\n  \n  return Response.json(post);\n}\n\nexport async function PATCH(request, { params }) {\n  const data = await request.json();\n  const post = await db.post.update({\n    where: { id: params.id },\n    data\n  });\n  return Response.json(post);\n}\n\nexport async function DELETE(request, { params }) {\n  await db.post.delete({ where: { id: params.id } });\n  return Response.json({ success: true });\n}\n\n// Handles: GET /api/posts/123, PATCH /api/posts/123, DELETE /api/posts/123</code></pre><p><strong>Features:</strong></p><ul><li>Supports all HTTP methods (GET, POST, PUT, PATCH, DELETE)</li><li>Access to request body, headers, cookies</li><li>Built-in response methods</li><li>Middleware support</li><li>Error handling</li></ul>"},

    // ==================== DATA FETCHING (18 questions) ====================
    {q: "What are the different data fetching strategies in Next.js?", d: "medium", a: "<p><strong>Four Main Strategies:</strong></p><ul><li><strong>SSG (getStaticProps):</strong> Fetch at build time, cache forever (or use ISR)</li><li><strong>SSR (getServerSideProps):</strong> Fetch per request</li><li><strong>CSR:</strong> Fetch in browser with useEffect</li><li><strong>ISR:</strong> Fetch at build time, revalidate periodically</li></ul><p><strong>Decision Tree:</strong></p><pre><code>Do you need different data for each user?\n  Yes → CSR or SSR\n  No → Can you generate at build time?\n    Yes → SSG (with ISR for updates)\n    No → SSR</code></pre><p><strong>Performance:</strong></p><ul><li><strong>Fastest:</strong> SSG (static files, no computation)</li><li><strong>Medium:</strong> ISR (cached + periodic updates)</li><li><strong>Slowest:</strong> SSR (compute per request)</li></ul>"},

    {q: "How do you use getStaticProps in Pages Router?", d: "medium", a: "<p><strong>getStaticProps:</strong> Fetch data at build time for static generation.</p><pre><code>// pages/posts/index.js\nexport async function getStaticProps() {\n  const posts = await fetchPosts();\n  \n  if (!posts.length) {\n    return { notFound: true }; // Return 404\n  }\n  \n  return {\n    props: { posts },\n    revalidate: 3600, // Revalidate every 1 hour (ISR)\n  };\n}\n\nexport default function Posts({ posts }) {\n  return (\n    &lt;div&gt;\n      {posts.map(post =&gt; (\n        &lt;article key={post.id}&gt;{post.title}&lt;/article&gt;\n      ))}\n    &lt;/div&gt;\n  );\n}</code></pre><p><strong>With Dynamic Routes:</strong></p><pre><code>// pages/posts/[id].js\nexport async function getStaticPaths() {\n  const posts = await fetchPosts();\n  \n  const paths = posts.map(post =&gt; ({\n    params: { id: post.id }\n  }));\n  \n  return {\n    paths,\n    fallback: 'blocking', // Generate missing on demand\n  };\n}\n\nexport async function getStaticProps({ params }) {\n  const post = await fetchPost(params.id);\n  \n  return {\n    props: { post },\n    revalidate: 3600,\n  };\n}\n\nexport default function Post({ post }) {\n  return &lt;article&gt;{post.title}&lt;/article&gt;;\n}</code></pre><p><strong>Fallback Options:</strong></p><ul><li><strong>false:</strong> Return 404 if not in paths (fast, limited)</li><li><strong>true:</strong> Show fallback, generate in background (slower initial, scales)</li><li><strong>'blocking':</strong> Generate on first request (slow first visit, then cached)</li></ul>"},

    {q: "How do you fetch data in Server Components (App Router)?", d: "medium", a: "<p><strong>Fetch Directly in Server Components:</strong> No special functions needed.</p><pre><code>// app/posts/page.js (Server Component by default)\nimport { sql } from '@vercel/postgres';\n\nexport default async function Posts() {\n  // Fetch directly - no getStaticProps needed\n  const { rows } = await sql`SELECT * FROM posts`;\n  \n  return (\n    &lt;div&gt;\n      {rows.map(post =&gt; (\n        &lt;article key={post.id}&gt;{post.title}&lt;/article&gt;\n      ))}\n    &lt;/div&gt;\n  );\n}</code></pre><p><strong>Automatic Caching:</strong> By default, fetch() results are cached.</p><pre><code>// This is cached by default\nconst res = await fetch('https://api.example.com/posts', {\n  next: { revalidate: 3600 } // Revalidate every hour\n});\n\nconst res = await fetch('https://api.example.com/posts', {\n  cache: 'no-cache' // Don't cache - fresh every request\n});\n\nconst res = await fetch('https://api.example.com/posts', {\n  cache: 'force-cache' // Cache indefinitely\n});</code></pre><p><strong>Dynamic vs Static:</strong></p><ul><li><strong>Static:</strong> fetch() with cache (default)</li><li><strong>Dynamic:</strong> fetch() without cache, or fetch in useEffect</li><li><strong>ISR:</strong> fetch() with revalidate</li></ul>"},

    {q: "How do you fetch data from within Client Components?", d: "easy", a: "<p><strong>Using useEffect Hook:</strong></p><pre><code>'use client';\n\nimport { useEffect, useState } from 'react';\n\nexport default function Posts() {\n  const [posts, setPosts] = useState([]);\n  const [loading, setLoading] = useState(true);\n  const [error, setError] = useState(null);\n  \n  useEffect(() => {\n    async function fetchData() {\n      try {\n        const res = await fetch('/api/posts');\n        if (!res.ok) throw new Error('Failed to fetch');\n        const data = await res.json();\n        setPosts(data);\n      } catch (err) {\n        setError(err.message);\n      } finally {\n        setLoading(false);\n      }\n    }\n    \n    fetchData();\n  }, []); // Run once on mount\n  \n  if (loading) return &lt;div&gt;Loading...&lt;/div&gt;;\n  if (error) return &lt;div&gt;Error: {error}&lt;/div&gt;;\n  \n  return (\n    &lt;div&gt;\n      {posts.map(post =&gt; (\n        &lt;article key={post.id}&gt;{post.title}&lt;/article&gt;\n      ))}\n    &lt;/div&gt;\n  );\n}</code></pre><p><strong>Using Library (SWR/React Query):</strong></p><pre><code>import useSWR from 'swr';\n\nfunction Posts() {\n  const { data: posts, error, isLoading } = useSWR('/api/posts', fetcher);\n  \n  if (isLoading) return &lt;div&gt;Loading...&lt;/div&gt;;\n  if (error) return &lt;div&gt;Error: {error.message}&lt;/div&gt;;\n  \n  return (\n    &lt;div&gt;\n      {posts.map(post =&gt; (\n        &lt;article key={post.id}&gt;{post.title}&lt;/article&gt;\n      ))}\n    &lt;/div&gt;\n  );\n}</code></pre>"},

    {q: "What is the difference between fetch and database queries in Server Components?", d: "hard", a: "<p><strong>Fetch:</strong> HTTP request to an endpoint (external or local).</p><pre><code>// Over the network\nconst res = await fetch('https://api.example.com/data');\nconst data = await res.json();</code></pre><p><strong>Database Queries:</strong> Direct connection to database (no HTTP).</p><pre><code>// Direct database access\nconst { rows } = await sql`SELECT * FROM posts`;\n// or\nconst data = await db.post.findMany();</code></pre><p><strong>When to Use Each:</strong></p><ul><li><strong>Fetch:</strong> Calling external APIs, calling Next.js API routes (though direct query is better)</li><li><strong>Database:</strong> Querying your own database from Server Components</li></ul><p><strong>Performance:</strong></p><ul><li><strong>Database:</strong> Faster (direct connection, no network overhead)</li><li><strong>Fetch to API Route:</strong> Slower (HTTP request, but can add caching)</li></ul><p><strong>Best Practice:</strong> Query database directly in Server Components. Only use fetch for external APIs.</p>"},

    {q: "How do you implement caching strategies in Next.js?", d: "hard", a: "<p><strong>Caching Hierarchy:</strong></p><ol><li><strong>Browser Cache:</strong> HTTP cache headers</li><li><strong>CDN Cache:</strong> Vercel Edge Network (for static)</li><li><strong>Server-side Cache:</strong> Data cache, Request cache</li></ol><p><strong>Data Cache (Built-in):</strong></p><pre><code>// Cached indefinitely\nconst res = await fetch('https://api.example.com/data');\n\n// Revalidate after 1 hour\nconst res = await fetch('https://api.example.com/data', {\n  next: { revalidate: 3600 }\n});\n\n// No cache - fresh every time\nconst res = await fetch('https://api.example.com/data', {\n  cache: 'no-cache'\n});</code></pre><p><strong>Request Deduplication:</strong> Same fetch called multiple times within request = single HTTP call.</p><pre><code>// Both calls result in single request\nconst res1 = await fetch('...');\nconst res2 = await fetch('...');\n\n// Force new request\nconst res = await fetch('...', { cache: 'no-store' });</code></pre><p><strong>Revalidation Strategies:</strong></p><pre><code>// Time-based (ISR)\nnext: { revalidate: 3600 }\n\n// On-demand revalidation\nimport { revalidatePath } from 'next/cache';\n\nexport async function createPost(data) {\n  const post = await db.post.create({ data });\n  revalidatePath('/posts'); // Revalidate /posts\n  return post;\n}</code></pre>"},

    {q: "What is the Next.js Font Optimization feature?", d: "medium", a: "<p><strong>next/font:</strong> Optimizes font loading automatically.</p><pre><code>// app/layout.js\nimport { Inter, Roboto } from 'next/font/google';\n\nconst inter = Inter({\n  subsets: ['latin'],\n  weight: ['400', '700'],\n  variable: '--font-inter', // CSS variable\n});\n\nconst roboto = Roboto({\n  subsets: ['latin'],\n  weight: '400',\n});\n\nexport default function RootLayout({ children }) {\n  return (\n    &lt;html lang='en' className={inter.variable}&gt;\n      &lt;body className={roboto.className}&gt;\n        {children}\n      &lt;/body&gt;\n    &lt;/html&gt;\n  );\n}</code></pre><p><strong>Benefits:</strong></p><ul><li>No layout shift (FOUT/FOIT eliminated)</li><li>Hosted on your domain (faster, no external requests)</li><li>Automatic subsetting (only needed characters)</li><li>Self-hosted (works offline)</li><li>Zero-runtime (fonts loaded at build time)</li></ul><p><strong>Local Fonts:</strong></p><pre><code>import localFont from 'next/font/local';\n\nconst myFont = localFont({\n  src: [\n    { path: './fonts/custom-bold.woff2', weight: '700' },\n    { path: './fonts/custom-regular.woff2', weight: '400' },\n  ],\n  variable: '--font-custom',\n});</code></pre>"},

    // ==================== OPTIMIZATION (15 questions) ====================
    {q: "What are Core Web Vitals and how do you optimize them in Next.js?", d: "hard", a: "<p><strong>Core Web Vitals:</strong> Three key metrics for user experience.</p><ul><li><strong>LCP (Largest Contentful Paint):</strong> Time when largest content element is visible (&lt; 2.5s good)</li><li><strong>FID (First Input Delay):</strong> Time from user input to page response (&lt; 100ms good)</li><li><strong>CLS (Cumulative Layout Shift):</strong> Unexpected layout shifts (&lt; 0.1 good)</li></ul><p><strong>Optimizations in Next.js:</strong></p><pre><code>// 1. Optimize Images (better LCP)\nimport Image from 'next/image';\n\n&lt;Image\n  src='/hero.jpg'\n  alt='Hero'\n  width={1920}\n  height={1080}\n  priority={true}  // Load immediately\n  sizes='100vw'\n/&gt;\n\n// 2. Code Splitting (better FID)\ndynamic(() =&gt; import('../components/HeavyComponent'), {\n  loading: () =&gt; &lt;p&gt;Loading...&lt;/p&gt;,\n});\n\n// 3. Prevent Layout Shift (better CLS)\n&lt;Image width={100} height={100} /&gt;  // Always specify\n&lt;video width={640} height={360} /&gt;  // Always specify\n\n// 4. Optimize Fonts (LCP)\nimport { Inter } from 'next/font/google';\nconst inter = Inter();</code></pre>"},

    {q: "How do you implement code splitting in Next.js?", d: "medium", a: "<p><strong>Automatic Code Splitting:</strong> Each page's JavaScript is separate (default).</p><pre><code>// pages/index.js - only loads code for home page\n// pages/about.js - only loads code for about page\n// pages/dashboard.js - only loads dashboard code</code></pre><p><strong>Dynamic Imports:</strong> Load components only when needed.</p><pre><code>import dynamic from 'next/dynamic';\n\nconst DynamicComponent = dynamic(\n  () =&gt; import('../components/expensive'),\n  { loading: () =&gt; &lt;p&gt;Loading...&lt;/p&gt; }\n);\n\nexport default function Home() {\n  return &lt;DynamicComponent /&gt;;\n}</code></pre><p><strong>Route-Based Splitting:</strong> Automatic per route (no config needed).</p><pre><code>// Bundle sizes:\n// /          50 KB\n// /about     45 KB\n// /dashboard 120 KB (no dashboard code loaded on home)</code></pre>"},

    {q: "What is the difference between static and dynamic rendering?", d: "hard", a: "<p><strong>Static Rendering:</strong> Page rendered at build time, same HTML for all users.</p><pre><code>// app/blog/page.js\nexport async function generateStaticParams() {\n  return [{ id: '1' }, { id: '2' }];\n}\n\nexport default async function Page({ params }) {\n  const post = await getPost(params.id);\n  return &lt;article&gt;{post.content}&lt;/article&gt;;\n}\n\n// Result: HTML generated at build time, cached forever</code></pre><p><strong>Dynamic Rendering:</strong> Page rendered per request.</p><pre><code>// Uses dynamic functions:\n// - cookies(), headers() \n// - searchParams (in client)\n// - fetch() without cache\n// - Real-time data\n\nexport default async function Page({ searchParams }) {\n  const data = await fetch(`/api/data?q=${searchParams.q}`, {\n    cache: 'no-cache'\n  });\n  return &lt;div&gt;{/* dynamic content */}&lt;/div&gt;;\n}\n\n// Result: HTML generated per request, not cached</code></pre>"},

    {q: "How do you optimize database queries in Next.js?", d: "hard", a: "<p><strong>Best Practices:</strong></p><pre><code>// 1. Use connection pooling\nimport { Pool } from 'pg';\nconst pool = new Pool({ max: 20 });\n\n// 2. Avoid N+1 queries\n// Bad:\nconst users = await db.user.findMany();\nconst posts = await Promise.all(\n  users.map(u =&gt; db.post.findMany({ where: { userId: u.id } }))\n);\n\n// Good:\nconst users = await db.user.findMany({\n  include: { posts: true }  // Single query with join\n});\n\n// 3. Caching\nconst posts = await db.post.findMany();\n// Automatically cached per request\n\n// 4. Pagination\nconst posts = await db.post.findMany({\n  skip: (page - 1) * 10,\n  take: 10,\n});\n\n// 5. Select only needed fields\nconst users = await db.user.findMany({\n  select: { id: true, name: true } // Not password!\n});</code></pre>"},

    {q: "What is streaming and how do you use it in Next.js?", d: "hard", a: "<p><strong>Streaming:</strong> Send HTML to browser before entire page is rendered.</p><pre><code>import { Suspense } from 'react';\n\nasync function SlowComponent() {\n  await new Promise(resolve =&gt; setTimeout(resolve, 3000));\n  return &lt;div&gt;Slow content&lt;/div&gt;;\n}\n\nexport default function Page() {\n  return (\n    &lt;&gt;\n      &lt;h1&gt;Fast content&lt;/h1&gt;\n      &lt;Suspense fallback={&lt;div&gt;Loading slow content...&lt;/div&gt;}&gt;\n        &lt;SlowComponent /&gt;\n      &lt;/Suspense&gt;\n    &lt;/&gt;\n  );\n}\n\n// Timeline:\n// 0ms   - HTML header and fast content sent\n// 3000ms- Slow component rendered and streamed\n// User sees page immediately, slow content later</code></pre><p><strong>Benefits:</strong></p><ul><li>Faster perceived page load</li><li>Better LCP</li><li>User sees content immediately</li></ul>"},

    {q: "How do you debug performance issues in Next.js?", d: "medium", a: "<p><strong>Using Next.js Analytics:</strong></p><pre><code>// app/layout.js\nimport { Analytics } from '@vercel/analytics/react';\n\nexport default function RootLayout({ children }) {\n  return (\n    &lt;html&gt;\n      &lt;body&gt;\n        {children}\n        &lt;Analytics /&gt;\n      &lt;/body&gt;\n    &lt;/html&gt;\n  );\n}</code></pre><p><strong>Web Vitals:</strong></p><pre><code>// app/web-vitals.js\nexport function register() {\n  if ('web-vital' in window) {\n    const { getCLS, getFID, getLCP } = await import('web-vitals');\n    \n    getCLS(console.log);\n    getFID(console.log);\n    getLCP(console.log);\n  }\n}</code></pre><p><strong>Bundle Analysis:</strong></p><pre><code>npm install --save-dev @next/bundle-analyzer\n\n// next.config.js\nconst withBundleAnalyzer = require('@next/bundle-analyzer')({\n  enabled: process.env.ANALYZE === 'true',\n});\n\nmodule.exports = withBundleAnalyzer(nextConfig);\n\n// Run: ANALYZE=true npm run build</code></pre>"},

    {q: "What are the best practices for CSS in Next.js?", d: "medium", a: "<p><strong>CSS Modules:</strong> Scoped styles per component.</p><pre><code>// button.module.css\n.button {\n  padding: 10px 20px;\n  background: blue;\n  color: white;\n}\n\n// button.js\nimport styles from './button.module.css';\n\nexport function Button() {\n  return &lt;button className={styles.button}&gt;Click&lt;/button&gt;;\n}</code></pre><p><strong>Tailwind CSS:</strong> Utility-first CSS framework.</p><pre><code>// app/globals.css\n@tailwind base;\n@tailwind components;\n@tailwind utilities;\n\n// Component\nexport function Button() {\n  return &lt;button className='px-5 py-2 bg-blue-500 text-white'&gt;Click&lt;/button&gt;;\n}</code></pre><p><strong>Global CSS:</strong> For global styles only.</p><pre><code>// app/globals.css\nbody {\n  font-family: system-ui;\n  margin: 0;\n  padding: 0;\n}\n\n// app/layout.js\nimport './globals.css';</code></pre><p><strong>Best Practices:</strong></p><ul><li>Use CSS Modules for component styles</li><li>Use Global CSS for resets and typography</li><li>Use Tailwind for utility classes</li><li>Avoid inline styles</li><li>Use CSS-in-JS if needed (emotion, styled-components)</li></ul>"},

    {q: "How do you handle error boundaries in Next.js?", d: "medium", a: "<p><strong>Error Boundary (App Router):</strong></p><pre><code>// app/error.js\n'use client';\n\nexport default function Error({ error, reset }) {\n  return (\n    &lt;div&gt;\n      &lt;h2&gt;Something went wrong!&lt;/h2&gt;\n      &lt;p&gt;{error.message}&lt;/p&gt;\n      &lt;button onClick={() =&gt; reset()}&gt;Try again&lt;/button&gt;\n    &lt;/div&gt;\n  );\n}</code></pre><p><strong>Nested Error Boundaries:</strong></p><pre><code>// app/dashboard/error.js - catches errors in /dashboard\n// app/error.js - catches errors in entire app</code></pre><p><strong>Not Found Boundary:</strong></p><pre><code>// app/not-found.js\nexport default function NotFound() {\n  return (\n    &lt;div&gt;\n      &lt;h1&gt;404 - Page Not Found&lt;/h1&gt;\n      &lt;a href='/'&gt;Go Home&lt;/a&gt;\n    &lt;/div&gt;\n  );\n}\n\n// Use in component:\nimport { notFound } from 'next/navigation';\n\nexport default function Page({ params }) {\n  const post = await getPost(params.id);\n  if (!post) notFound();\n  return &lt;article&gt;{post.content}&lt;/article&gt;;\n}</code></pre>"},

    {q: "How do you deploy a Next.js application?", d: "medium", a: "<p><strong>Vercel (Recommended):</strong> One-click deployment from GitHub.</p><pre><code>1. Push to GitHub\n2. Connect GitHub to Vercel\n3. Vercel auto-deploys on push\n4. Environment variables in dashboard\n5. Serverless functions auto-generated</code></pre><p><strong>Self-Hosted (Node.js):</strong></p><pre><code>// Build\nnpm run build\n\n// Run on server\nNODE_ENV=production node .next/standalone/server.js\n\n// With PM2\npm2 start server.js --name 'nextjs-app'\npm2 startup\npm2 save</code></pre><p><strong>Docker:</strong></p><pre><code>// Dockerfile\nFROM node:18-alpine\n\nWORKDIR /app\nCOPY package.json package-lock.json ./\nRUN npm ci --only=production\nCOPY .next .next\n\nEXPOSE 3000\nCMD [\"npm\", \"run\", \"start\"]</code></pre><p><strong>Database & Secrets:</strong></p><pre><code>// Environment variables in Vercel dashboard\nDATABASE_URL=postgresql://...\nNEXT_PUBLIC_API_URL=https://api.example.com\n\n// .env.local (local development only)\n// .env.production (Vercel uses dashboard values)</code></pre>"},

    {q: "What is incremental static regeneration (ISR) and how do you use it?", d: "hard", a: "<p><strong>ISR:</strong> Combine static generation with periodic updates.</p><pre><code>// Pages Router\nexport async function getStaticProps() {\n  return {\n    props: { data },\n    revalidate: 3600  // Regenerate every 1 hour\n  };\n}\n\n// App Router\nexport const revalidate = 3600;</code></pre><p><strong>On-Demand Revalidation:</strong></p><pre><code>// Trigger revalidation without waiting\nimport { revalidatePath, revalidateTag } from 'next/cache';\n\n// Revalidate path\nexport async function updatePost(id, data) {\n  const post = await db.post.update({ where: { id }, data });\n  revalidatePath(`/posts/${id}`);\n  return post;\n}\n\n// Tag-based revalidation\n// Fetch with tag\nconst posts = await fetch('...', {\n  next: { tags: ['posts'] }\n});\n\n// Revalidate all tagged\nrevalidateTag('posts');</code></pre><p><strong>Benefits:</strong></p><ul><li>Static performance + fresh data</li><li>No full rebuild needed</li><li>Scales to millions of pages</li></ul>"},

    {q: "How do you use Next.js with TypeScript?", d: "medium", a: "<p><strong>Setup (Zero Config):</strong> Create tsconfig.json and use .tsx files.</p><pre><code>// app/page.tsx\nimport { ReactNode } from 'react';\n\ninterface Props {\n  children: ReactNode;\n}\n\nexport default function Home({ children }: Props) {\n  return &lt;main&gt;{children}&lt;/main&gt;;\n}</code></pre><p><strong>Type-Safe Props:</strong></p><pre><code>// app/posts/[id]/page.tsx\ninterface Props {\n  params: { id: string };\n  searchParams: { [key: string]: string | string[] };\n}\n\nexport default function Post({ params, searchParams }: Props) {\n  return &lt;article&gt;Post {params.id}&lt;/article&gt;;\n}\n\nexport async function generateStaticParams() {\n  const posts = await getPosts();\n  return posts.map(post =&gt; ({\n    id: post.id.toString()\n  }));\n}</code></pre><p><strong>API Routes with TypeScript:</strong></p><pre><code>// app/api/posts/route.ts\nimport { NextRequest, NextResponse } from 'next/server';\n\nexport async function GET(request: NextRequest) {\n  const posts = await db.post.findMany();\n  return NextResponse.json(posts);\n}\n\nexport async function POST(request: NextRequest) {\n  const data = await request.json();\n  const post = await db.post.create({ data });\n  return NextResponse.json(post, { status: 201 });\n}</code></pre>"},

    {q: "What are some common Next.js pitfalls and how to avoid them?", d: "hard", a: "<p><strong>1. Using array index as key in lists:</strong></p><pre><code>// Bad\n{items.map((item, index) =&gt; (\n  &lt;li key={index}&gt;{item}&lt;/li&gt;\n))}\n\n// Good\n{items.map(item =&gt; (\n  &lt;li key={item.id}&gt;{item.name}&lt;/li&gt;\n))}</code></pre><p><strong>2. Not setting width/height on images:</strong></p><pre><code>// Bad\n&lt;img src='/image.jpg' /&gt;\n\n// Good\n&lt;Image src='/image.jpg' width={400} height={300} alt='' /&gt;</code></pre><p><strong>3. Fetching in client useEffect without dependencies:</strong></p><pre><code>// Bad - fetches every render\nuseEffect(() =&gt; {\n  fetch('/api/data');\n});\n\n// Good\nuseEffect(() =&gt; {\n  fetch('/api/data');\n}, []); // Runs once</code></pre><p><strong>4. Using external packages in Server Components unnecessarily:</strong></p><pre><code>// Adds to bundle\nconst crypto = await import('crypto');\n\n// Better - use Node.js APIs directly\nimport crypto from 'crypto';</code></pre><p><strong>5. Not using dynamic imports for large components:</strong></p><pre><code>// Slows initial load\nimport HeavyChart from './heavy-chart';\n\n// Better\nconst HeavyChart = dynamic(() =&gt; import('./heavy-chart'));</code></pre>"}
  ]
};
